    if (requiredOptions == null || requiredOptions.isEmpty()) {
        return; // No required options to check
    }

    // Initialize a buffer to build the error message
    StringBuilder buff = new StringBuilder("Missing required option");
    buff.append(requiredOptions.size() == 1 ? "" : "s");
    buff.append(": ");

    // Loop through the required options and append them to the buffer
    for (int i = 0; i < requiredOptions.size(); i++) {
        Object option = requiredOptions.get(i);
        if (option != null) {
            buff.append(option);
